import{_ as t,o as r,c as s,ag as a}from"./chunks/framework.D9bIGSBm.js";const h=JSON.parse('{"title":"移动端配对（LoongCode App）","description":"","frontmatter":{},"headers":[],"relativePath":"settings/mobile-pairing.md","filePath":"settings/mobile-pairing.md"}'),l={name:"settings/mobile-pairing.md"};function n(e,o,i,g,d,p){return r(),s("div",null,[...o[0]||(o[0]=[a('<h1 id="移动端配对-loongcode-app" tabindex="-1">移动端配对（LoongCode App） <a class="header-anchor" href="#移动端配对-loongcode-app" aria-label="Permalink to &quot;移动端配对（LoongCode App）&quot;">​</a></h1><p><strong>入口：</strong> 设置 → <strong>移动端配对</strong>（侧边栏手机图标）</p><p>移动端配对让你把官方的 <strong>LoongCode App</strong>（手机端伴侣应用）与本机电脑绑定，离开电脑时也能用手机远程查看与驱动电脑上的 AI 任务。它通过一个<strong>中转服务</strong>在手机与电脑之间转发消息，所有内容<strong>端到端加密</strong>——中转服务看不到明文。</p><blockquote><p>电脑始终是「大脑」：CLI 子进程、会话历史与项目文件都留在电脑上，手机只是远程的输入与查看端。</p></blockquote><div class="warning custom-block"><p class="custom-block-title">安全提醒：配对即授予操作权限</p><p>完成配对的手机可以远程让电脑上的 AI <strong>修改、删除文件并运行命令</strong>。请只与你本人持有的手机配对，妥善保管配对二维码，并在不再使用某台设备时及时<strong>解绑</strong>。</p></div><div class="tip custom-block"><p class="custom-block-title">与「机器人渠道」的区别</p><p><a href="/docs/settings/bots.html">机器人渠道</a>（微信 / 飞书）是把即时通讯消息转发给 AI，面向纯文本交互；<strong>移动端配对</strong>则是专用的 LoongCode App，支持实时事件流、历史回放、富输入（斜杠命令 / @文件 / 图片）与任务配置同步等更完整的能力。两者相互独立，可按需选用。</p></div><hr><h2 id="工作原理" tabindex="-1">工作原理 <a class="header-anchor" href="#工作原理" aria-label="Permalink to &quot;工作原理&quot;">​</a></h2><ol><li>电脑（PC 端）通过一个<strong>中转服务</strong>接入网络，并生成配对二维码。</li><li>手机上的 LoongCode App 扫码完成配对，与电脑建立端到端加密通道。</li><li>之后手机即可远程浏览电脑的工作区与任务、打开任务回放历史、发送消息并实时看到 AI 的流式回复。</li></ol><p>中转服务只负责盲转发加密数据，无法读取消息内容；密钥与凭据只保存在电脑本地，前端界面只展示绑定状态与时间戳。</p><hr><h2 id="配置步骤" tabindex="-1">配置步骤 <a class="header-anchor" href="#配置步骤" aria-label="Permalink to &quot;配置步骤&quot;">​</a></h2><p>移动端配对页从上到下分为三个区块：<strong>中转服务器配置</strong>、<strong>配对二维码</strong>、<strong>已配对设备</strong>。</p><h3 id="_1-中转服务器配置" tabindex="-1">1. 中转服务器配置 <a class="header-anchor" href="#_1-中转服务器配置" aria-label="Permalink to &quot;1. 中转服务器配置&quot;">​</a></h3><table tabindex="0"><thead><tr><th>字段</th><th>说明</th></tr></thead><tbody><tr><td><strong>中转地址</strong></td><td><strong>留空</strong>即使用 LoongCode 官方公共中转，开箱即用；如需自建，可填入私有部署的 <code>ws://</code> / <code>wss://</code> 地址</td></tr><tr><td><strong>令牌</strong></td><td>使用官方公共中转时<strong>留空</strong>；私有部署若设置了访问令牌则在此填写</td></tr></tbody></table><p>填好后点击 <strong>保存并连接中转</strong>。保存成功后下方会显示连接状态：</p><ul><li><strong>已连接中转站</strong>（绿色）：与中转服务连接正常。</li><li><strong>中转已保存，正在连接…</strong>：正在建立连接，稍候即可。</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>绝大多数用户无需填写任何地址与令牌——直接留空保存即可走官方公共中转。中转地址与令牌仅在私有部署场景下才需要填写。</p></div><h3 id="_2-配对二维码" tabindex="-1">2. 配对二维码 <a class="header-anchor" href="#_2-配对二维码" aria-label="Permalink to &quot;2. 配对二维码&quot;">​</a></h3><p>中转连接就绪后，<strong>生成配对二维码</strong> 按钮才可用。点击后页面显示一个二维码：</p><ol><li>打开手机上的 <strong>LoongCode App</strong>。</li><li>用 App 扫描电脑屏幕上的二维码。</li><li>App 提示配对成功后，该设备会出现在下方的「已配对设备」列表中。</li></ol><p>二维码内含一次性配对码（短时有效），用于完成密钥协商；过期后重新点击<strong>生成配对二维码</strong>即可刷新。</p><h3 id="_3-已配对设备" tabindex="-1">3. 已配对设备 <a class="header-anchor" href="#_3-已配对设备" aria-label="Permalink to &quot;3. 已配对设备&quot;">​</a></h3><p>列出当前已绑定的所有设备，每条显示设备名称与配对日期：</p><ul><li>点击右上角 <strong>刷新</strong> 重新拉取列表。</li><li>点击设备行末的 <strong>解绑</strong> 即可移除该设备；解绑后该设备需重新扫码才能再次使用。</li></ul><hr><h2 id="在手机上能做什么" tabindex="-1">在手机上能做什么 <a class="header-anchor" href="#在手机上能做什么" aria-label="Permalink to &quot;在手机上能做什么&quot;">​</a></h2><p>完成配对后，LoongCode App 可以远程操作电脑上的任务：</p><ul><li><strong>浏览工作区与任务</strong>：查看电脑上的真实工作区列表，以及各工作区下任务的实时状态（空闲 / 运行中 / 提问中）。</li><li><strong>打开任务并回放历史</strong>：打开一条既有任务即加载最近的对话历史，上滑可分页加载更早的消息，用户气泡 / 助手气泡 / 工具调用气泡分别呈现。</li><li><strong>新建任务</strong>：直接从手机发起新任务，标题自动取首条消息摘要。</li><li><strong>实时收发消息</strong>：在手机上发送的消息会注入电脑端的 AI 会话，AI 的流式回复实时同步到手机。无论消息从手机还是电脑发出，两端都保持一致。</li><li><strong>富输入</strong>：行首输入 <code>/</code> 调出<strong>斜杠命令</strong>面板（含电脑端真实的命令 / 技能 / 工作流）、输入 <code>@关键字</code> <strong>搜索并引用工作区文件</strong>、以及从相册或拍照<strong>发送图片</strong>。</li><li><strong>回答提问与权限审批</strong>：AI 抛出的提问（AskUserQuestion）与命令 / 改文件的权限请求会同步到手机，可在手机上直接作答或批准 / 拒绝，结果实时回灌到电脑端。</li><li><strong>任务配置同步</strong>：在手机上调整任务的 CLI、模型、推理强度与权限预设（「调校四件套」），改动落到电脑端并在下一轮生效；电脑端在桌面 GUI 上的同类改动也会实时同步回手机。</li></ul><div class="tip custom-block"><p class="custom-block-title">本地任务隔离</p><p>你在<strong>电脑上</strong>直接新建的任务，默认不会主动推送到手机；只有在手机上<strong>打开</strong>该任务后，电脑才开始向手机推送它的实时事件。关闭任务对话即停止推送。</p></div><hr><h2 id="连接稳定性" tabindex="-1">连接稳定性 <a class="header-anchor" href="#连接稳定性" aria-label="Permalink to &quot;连接稳定性&quot;">​</a></h2><ul><li>网络抖动时，电脑会自动重连中转服务并补发未确认的消息，短暂断网不丢消息。</li><li>电脑与中转之间有应用层心跳与空闲检测，能及时发现并修复「假在线」状态。</li><li>临时网络波动<strong>不会清除配对凭据</strong>；只有明确的鉴权失效才需要重新配对。</li></ul><hr><h2 id="已知限制" tabindex="-1">已知限制 <a class="header-anchor" href="#已知限制" aria-label="Permalink to &quot;已知限制&quot;">​</a></h2><ul><li>当前为初期版本，更多电脑端能力（如终端、文件、Git 的远程操作）仍在后续规划中。</li><li>富输入中的 <code>@文件</code> 在 worktree 任务下以工作区根目录为基准解析相对路径。</li><li>所有模型交互仍由电脑本机的 CLI 子进程（Claude Code / Codex）完成，中转服务与 LoongCode 均不直接访问模型 API。</li></ul><hr><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li><a href="/docs/settings/bots.html">机器人渠道</a> — 通过微信 / 飞书机器人接入移动端纯文本交互</li><li><a href="/docs/features/tasks-and-workspaces.html">任务与工作区</a> — 了解远程驱动的任务在应用内如何组织与管理</li><li><a href="/docs/features/permissions.html">权限与审批</a> — 了解权限请求的工作方式</li></ul>',39)])])}const u=t(l,[["render",n]]);export{h as __pageData,u as default};
